INSERT INTO DOI_RND_SUBUL (YYYYMM,SEL_CODE,SITE,구분,구분_ord,도우코드,도우모델,작업구분,org작업구분,model,Inch,Dw_Site,BOH_MONTH,IN_MONTH,BONUS_MONTH,EOH_MONTH,OUT_MONTH,LOSS_MONTH,NG_MONTH,수율제외_MONTH,REWORK진행_MONTH,SHIPPING_PLAN_MONTH,SHIPPING_ACTUAL_MONTH,material_loss)
SELECT YYYYMM,SEL_CODE,SITE,구분,구분_ord,도우코드,도우모델,작업구분,org작업구분,model,Inch,Dw_Site,BOH_MONTH,IN_MONTH,BONUS_MONTH,EOH_MONTH,OUT_MONTH,LOSS_MONTH,NG_MONTH,수율제외_MONTH,REWORK진행_MONTH,SHIPPING_PLAN_MONTH,SHIPPING_ACTUAL_MONTH,material_loss
FROM (
SELECT *, MAX(seq_no) over (partition by YYYYMM, SEL_CODE, SITE, 도우코드) max_seq_no FROM #TempTable
) A
WHERE 1=1
AND seq_no = max_seq_no
AND NOT EXISTS (
	SELECT 1
	FROM DOI_RND_SUBUL b
	WHERE 1=1
	AND b.YYYYMM = a.YYYYMM
	AND b.SEL_CODE = a.SEL_CODE
	AND b.SITE = a.SITE
	AND b.도우코드 = a.도우코드
);

DROP TABLE #TempTable;

INSERT INTO DOI_RND_SUBUL
(
	YYYYMM,SEL_CODE,SITE,구분,구분_ord,도우코드,도우모델,작업구분,org작업구분,model,Inch,Dw_Site,BOH_MONTH,IN_MONTH,BONUS_MONTH,EOH_MONTH,OUT_MONTH,LOSS_MONTH,NG_MONTH,수율제외_MONTH,REWORK진행_MONTH,SHIPPING_PLAN_MONTH,SHIPPING_ACTUAL_MONTH,material_loss























)
VALUES
(
#{yyyymm}
, #{selCode}
, CASE WHEN #{site}='본사' Then 'HQ'  WHEN #{site}='VINA' then 'VN' else left(#{site},2) end
, #{구분}
, #{구분Ord}
, #{도우코드}
, #{도우모델}
, #{작업구분}
, #{org작업구분}
, #{model}
, #{inch}
, #{dwSite}
, #{bohMonth}
, #{inMonth}
, #{bonusMonth}
, #{eohMonth}
, #{outMonth}
, #{lossMonth}
, #{ngMonth}
, #{수율제외Month}
, #{rework진행Month}
, #{shippingPlanMonth}
, #{shippingActualMonth}
, #{materialLoss}
);

